/// Wraps Python -> Rust `PathResolver` trait.
#[cfg(feature = "py-hook-adapters")]
pub(crate) struct PyPathResolverAdapter {
    inner: Py<PyAny>,
}

#[cfg(feature = "py-hook-adapters")]
unsafe impl Send for PyPathResolverAdapter {}
#[cfg(feature = "py-hook-adapters")]
unsafe impl Sync for PyPathResolverAdapter {}

#[cfg(feature = "py-hook-adapters")]
impl PathResolver for PyPathResolverAdapter {
    fn try_read(&self, path: &str) -> Option<Vec<u8>> {
        Python::attach(|py| {
            let result = self.inner.call_method1(py, "try_read", (path,)).ok()?;
            if result.is_none(py) {
                return None;
            }
            result.extract::<Vec<u8>>(py).ok()
        })
    }

    fn try_write(&self, path: &str, content: &[u8]) -> Option<()> {
        Python::attach(|py| {
            self.inner
                .call_method1(py, "try_write", (path, content))
                .ok()?;
            Some(())
        })
    }

    fn try_delete(&self, path: &str) -> Option<()> {
        Python::attach(|py| {
            self.inner.call_method1(py, "try_delete", (path,)).ok()?;
            Some(())
        })
    }
}

// ── PyPermissionProviderAdapter ──────────────────────────────────────

use crate::kernel::core::dispatch::{Permission, PermissionDecision, PermissionProvider};

pub(crate) struct PyPermissionProviderAdapter {
    checker: Py<PyAny>,
}

unsafe impl Send for PyPermissionProviderAdapter {}

unsafe impl Sync for PyPermissionProviderAdapter {}

impl PermissionProvider for PyPermissionProviderAdapter {
    fn check(
        &self,
        path: &str,
        permission: Permission,
        _ctx: &crate::contracts::OperationContext,
    ) -> PermissionDecision {
        Python::attach(|py| {
            let checker = self.checker.bind(py);
            let perm_mod = match py.import("nexus.contracts.types") {
                Ok(m) => m,
                Err(_) => return PermissionDecision::Unknown,
            };
            let perm_cls = match perm_mod.getattr("Permission") {
                Ok(c) => c,
                Err(_) => return PermissionDecision::Unknown,
            };
            let py_perm = match perm_cls.getattr(permission.as_str()) {
                Ok(p) => p,
                Err(_) => return PermissionDecision::Unknown,
            };
            let py_ctx = match rust_ctx_to_python(py, _ctx, "") {
                Ok(c) => c,
                Err(_) => return PermissionDecision::Unknown,
            };
            match checker.call_method1("check", (path, py_perm, py_ctx)) {
                Ok(_) => PermissionDecision::Allow,
                Err(_) => PermissionDecision::Deny(format!(
                    "permission denied: {} on '{}'",
                    permission.as_str(),
                    path
                )),
            }
        })
    }
}

