    fn stream_read_batch<'py>(
        &self,
        py: Python<'py>,
        path: &str,
        offset: usize,
        count: usize,
    ) -> PyResult<(Vec<Bound<'py, PyBytes>>, usize)> {
        let (msgs, next) = self
            .inner
            .stream_read_batch(path, offset, count)
            .map_err(|e| -> PyErr { e.into() })?;
        let py_msgs: Vec<Bound<'py, PyBytes>> = msgs.iter().map(|m| PyBytes::new(py, m)).collect();
        Ok((py_msgs, next))
    }

