        // 2. Call pure Rust kernel
        let rust_ctx = ctx.to_rust();
        let result = py.detach(|| self.inner.sys_rename(old_path, new_path, &rust_ctx));
        let result = result.map_err(|e| -> PyErr { e.into() })?;

